 1	import * as React from 'react';
 2	
 3	import { modelToGroupVersionKind, ServiceModel } from '@kubevirt-ui/kubevirt-api/console';
 4	import { IoK8sApiCoreV1Service } from '@kubevirt-ui/kubevirt-api/kubernetes/models';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { getServicesForVmi } from '@kubevirt-utils/resources/vmi';
 7	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 8	import { ServicesList } from '@openshift-console/dynamic-plugin-sdk-internal';
 9	import { Icon, Title } from '@patternfly/react-core';
10	import { LinkIcon } from '@patternfly/react-icons';
11	
12	const Services = ({ pathname, vmi }) => {
13	  const { t } = useKubevirtTranslation();
14	
15	  const [services, loaded] = useK8sWatchResource<IoK8sApiCoreV1Service[]>({
16	    groupVersionKind: modelToGroupVersionKind(ServiceModel),
17	    isList: true,
18	    namespace: vmi?.metadata?.namespace,
19	  });
20	
21	  const data = getServicesForVmi(services, vmi);
22	
23	  return (
24	    <div>
25	      <a className="link-icon" href={`${pathname}#services`}>
26	        <Icon size="sm">
27	          <LinkIcon />
28	        </Icon>
29	      </a>
30	      <Title className="co-section-heading" headingLevel="h2">
31	        {t('Services')}
32	      </Title>
33	      <ServicesList data={data || []} loaded={loaded} />
34	    </div>
35	  );
36	};
37	
38	export default Services;

